const IVX_ALLOWED_ORIGINS = [
  'https://ivxholding.com',
  'https://www.ivxholding.com',
  'https://chat.ivxholding.com',
  'http://localhost:8081',
  'http://localhost:3000',
  'http://localhost:5173',
  'http://127.0.0.1:8081',
  'http://127.0.0.1:3000',
];

app.use('*', cors({
  origin: (origin: string) => {
    if (!origin || IVX_ALLOWED_ORIGINS.includes(origin)) return origin;
    return null;
